// GSC date x country -> fact_seo_daily rows at date x region grain.
const resp = $input.first().json;
const rows = resp.rows || [];

// GSC country dimension is ISO 3166-1 alpha-3, lowercase
function regionFromAlpha3(cc) {
  const c = String(cc || '').toLowerCase();
  if (['gbr', 'irl', 'imn', 'ggy', 'jey'].includes(c)) return 'UKI';
  if (['bel', 'lux'].includes(c)) return 'BeLux';
  if (c === 'nld') return 'NL';
  return 'UNASSIGNED';
}

const agg = {};
let issues = 0;
for (const r of rows) {
  const keys = r.keys || [];
  const date = String(keys[0] || '');
  if (date.length !== 10) { issues++; continue; }
  const region = regionFromAlpha3(keys[1]);
  const k = date + '|' + region;
  if (!agg[k]) {
    agg[k] = { activity_date: date, region_code: region, clicks: 0, impressions: 0,
      pos_weight: 0, source: 'gsc' };
  }
  const a = agg[k];
  const impr = Number(r.impressions) || 0;
  a.clicks += Number(r.clicks) || 0;
  a.impressions += impr;
  a.pos_weight += (Number(r.position) || 0) * impr;
}

const out = Object.values(agg).map((a) => ({
  activity_date: a.activity_date,
  region_code: a.region_code,
  clicks: a.clicks,
  impressions: a.impressions,
  ctr: a.impressions ? Number((a.clicks / a.impressions).toFixed(6)) : 0,
  avg_position: a.impressions ? Number((a.pos_weight / a.impressions).toFixed(2)) : 0,
  source: a.source
}));
if (out.length === 0) {
  throw new Error('GSC returned 0 usable rows - check site URL format (sc-domain: vs URL-prefix), access grant and date range');
}
const meta = { rows_in: rows.length, issues: issues };
return out.map((json) => ({ json: Object.assign({}, json, { _meta: meta }) }));

// GSC date x page -> fact_seo_page_daily rows.
const resp = $input.first().json;
const rows = resp.rows || [];
const out = [];
let issues = 0;
for (const r of rows) {
  const keys = r.keys || [];
  const date = String(keys[0] || '');
  const page = String(keys[1] || '');
  if (date.length !== 10 || !page) { issues++; continue; }
  out.push({
    activity_date: date,
    page: page,
    clicks: Number(r.clicks) || 0,
    impressions: Number(r.impressions) || 0,
    ctr: Number(r.ctr) || 0,
    avg_position: Number((Number(r.position) || 0).toFixed(2)),
    source: 'gsc'
  });
}
if (out.length === 0) {
  throw new Error('GSC top-pages query returned 0 usable rows - check site URL and access');
}
const meta = { rows_in: rows.length, issues: issues };
return out.map((json) => ({ json: Object.assign({}, json, { _meta: meta }) }));
